import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";
import therapistResponses from "../data/therapistResponses";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
    },
  ]);
  const [input, setInput] = useState("");
  const [typing, setTyping] = useState(false);

  const messagesEndRef = useRef(null);

  // Auto scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, typing]);

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setTyping(true);

    setTimeout(() => {
      const reply =
        therapistResponses[
          Math.floor(Math.random() * therapistResponses.length)
        ];

      setMessages((prev) => [
        ...prev,
        { sender: "bot", text: reply },
      ]);
      setTyping(false);
    }, 1200);
  };

  return (
    <div className="general-chat-page">
      <div className="general-chat-container">
        {/* Header */}
        <div className="chat-header">
          <h2>🧠 General Chat</h2>
          <p>❤️ Listening</p>
        </div>

        {/* Messages */}
        <div className="chat-messages">
          {messages.map((msg, index) => (
            <div
              key={index}
              className={
                msg.sender === "user" ? "user-message" : "bot-message"
              }
            >
              {msg.text}
            </div>
          ))}

          {typing && (
            <div className="typing-indicator">AI is typing...</div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="chat-input-container">
          <input
            type="text"
            placeholder="Type how you feel..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>
      </div>
    </div>
  );
};

export default GeneralChat;
